SELECT a.app_name, a.app_type, pm.metric_name, pm.unit
FROM applications a
INNER JOIN performance_metrics pm ON a.app_id = pm.app_id;

SELECT app_id, metric_name, value, unit
FROM system_metrics
WHERE metric_name = 'memory usage' AND value > 1024;

SELECT u.user_id, u.user_name, n.notification_type
FROM users u
JOIN notifications n ON u.email = n.recipient;

SELECT timeStamp, elapsed, label, responseMessage 
FROM timestamp 
WHERE elapsed > SINH(500);

SELECT user_id, app_id, feedback_message, created_date 
FROM user_feedback 
WHERE rating = 1;

SELECT 
    (SELECT AVG(latency) FROM latencies WHERE app_id = 1) AS avg_latency,
    (SELECT AVG(elapsed) FROM timestamp WHERE app_id = 1) AS avg_response_time;

SELECT applications.app_name, system_metrics.value
FROM applications
JOIN system_metrics ON applications.app_id = system_metrics.app_id;

SELECT latency_id, timeStamp, latency
FROM latencies
WHERE app_id = 1 AND latency > 1000;

SELECT AVG(latency) AS Average_Latency
FROM latencies
WHERE app_id = 1;

SELECT DISTINCT app_name
FROM applications
WHERE app_id IN (SELECT DISTINCT app_id FROM user_feedback);
